CREATE OR REPLACE VIEW vr_nsk_010_006000 (balance_date, member_group_no, member_group_name, member_status_code, member_status_name, count_mem, share_balance) AS SELECT  sc_rep_mem_share_loan_bal.balance_date,
        sc_mem_m_ucf_member_group.member_group_no,
         sc_mem_m_ucf_member_group.member_group_name,   
         sc_mem_m_ucf_member_status.member_status_code,   
