   WHERE ( sc_rep_mem_share_loan_bal.member_group_no = sc_mem_m_ucf_member_group.member_group_no ) and ( sc_rep_mem_share_loan_bal.member_status_code = sc_mem_m_ucf_member_status.member_status_code ) and ( sc_rep_mem_share_loan_bal.share_balance <> 0 )  
